// Prepare nutrition data for AI analysis
const userData = $input.all();
const nutritionReports = [];

for (const user of userData) {
  const data = user.json;

  // Calculate macro percentages
  const caloriePercentage = Math.round((data.total_calories / data.daily_calorie_target) * 100);
  const proteinPercentage = Math.round((data.total_protein / data.daily_protein_target) * 100);
  const carbsPercentage = Math.round((data.total_carbs / data.daily_carbs_target) * 100);
  const fatPercentage = Math.round((data.total_fat / data.daily_fat_target) * 100);

  // Determine performance level
  let performanceLevel = 'Excellent';
  let emoji = '🎉';

  if (caloriePercentage < 60) {
    performanceLevel = 'Needs Improvement';
    emoji = '💪';
  } else if (caloriePercentage < 80) {
    performanceLevel = 'Good';
    emoji = '👍';
  } else if (caloriePercentage > 120) {
    performanceLevel = 'Exceeded';
    emoji = '⚠️';
  }

  const nutritionReport = {
    user_id: data.id,
    email: data.email,
    name: data.name,
    date: new Date().toLocaleDateString(),
    performance: {
      level: performanceLevel,
      emoji: emoji,
      calorie_percentage: caloriePercentage,
      protein_percentage: proteinPercentage,
      carbs_percentage: carbsPercentage,
      fat_percentage: fatPercentage
    },
    targets: {
      calories: data.daily_calorie_target,
      protein: data.daily_protein_target,
      carbs: data.daily_carbs_target,
      fat: data.daily_fat_target
    },
    actuals: {
      calories: data.total_calories,
      protein: data.total_protein,
      carbs: data.total_carbs,
      fat: data.total_fat,
      meals_logged: data.meals_logged || 0,
      water_intake_ml: data.water_intake || 0
    },
    hydration: {
      intake_ml: data.water_intake || 0,
      goal_ml: 2000,
      percentage: Math.round(((data.water_intake || 0) / 2000) * 100)
    }
  };

  nutritionReports.push(nutritionReport);
}

return nutritionReports.map(report => ({ json: report }));

