// Process AI response and prepare email content
const aiResponses = $input.all();
const emailContents = [];

for (const response of aiResponses) {
  const userData = response.json;

  // Parse AI response safely
  let aiAnalysis;
  try {
    aiAnalysis = JSON.parse(response.json.message.content);
  } catch (error) {
    console.log('AI Response parsing error:', error);
    // Fallback content if AI fails
    aiAnalysis = {
      assessment: 'Your nutrition tracking is going well!',
      insights: 'Continue monitoring your macros for optimal results.',
      hydration: 'Remember to stay hydrated throughout the day.',
      recommendations: 'Focus on hitting your protein targets tomorrow.',
      motivation: 'You\'re making great progress on your health journey!'
    };
  }

  // Create email content with AI insights
  const emailContent = {
    user_id: userData.user_id,
    email: userData.email,
    name: userData.name,
    date: userData.date,
    performance: userData.performance,
    targets: userData.targets,
    actuals: userData.actuals,
    hydration: userData.hydration,
    ai_insights: aiAnalysis,
    email_subject: `🥗 AI Nutrition Report - ${userData.name} - ${userData.date}`
  };

  emailContents.push(emailContent);
}

return emailContents.map(content => ({ json: content }));
